#!/usr/bin/env ruby

# We have run tp1_summarise in parallel and have a bunch of files
# generated by the -T option and want to aggregate those.

def tp1_concat(fnames)
  result = Hash.new(0)
  fnames.each do |fname|
    File.foreach(fname) do | line|
      f = line.chomp.split
      result[f[1]] += f[0].to_i

    end
  end

  result.each do |k, v|
    $stdout << "#{v} #{k}\n"
  end
end

tp1_concat(ARGV)
